import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Users, Settings,
  RefreshCw, ArrowRightLeft, Shield
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

// ─── SAFE ERROR EXTRACTOR ────────────────────────────────────────────────────
const getErrMsg = (err) => {
  const d = err.response?.data;
  if (d?.error?.message) return d.error.message;
  if (typeof d?.error === 'string') return d.error;
  if (typeof d?.message === 'string') return d.message;
  return err.message || 'An unexpected error occurred';
};

// ─── INLINE MODAL ────────────────────────────────────────────────────────────
const InlineModal = ({ title, onClose, children }) => (
  <div style={{ position: 'fixed', top:0, left:0, right:0, bottom:0, background:'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
    <div className="card" style={{ width: '100%', maxWidth: 500, maxHeight: '90vh', overflowY: 'auto', background: '#fff', borderRadius: 8 }}>
      <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem', borderBottom: '1px solid #eee' }}>
         <div className="card-title" style={{ fontWeight: 600, fontSize: '1.1rem', margin: 0 }}>{title}</div>
         <button className="btn btn-ghost" style={{ padding: 4, background: 'none', border: 'none', cursor: 'pointer' }} onClick={onClose}><X size={18}/></button>
      </div>
      <div style={{ padding: '1rem' }}>
        {children}
      </div>
    </div>
  </div>
);

// ─── STATUS HELPERS ──────────────────────────────────────────────────────────
const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  APPROVED: 'Approved', REJECTED: 'Rejected', CANCELLED: 'Cancelled',
};

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  return normStatus(reqStatus) === normStatus(filterValue);
};
const isFinalStatus = s => ['APPROVED','REJECTED','CANCELLED'].includes(normStatus(s));

const toArr = (r) => {
  if (!r) return [];
  const d = r.data?.data || r.data?.requests || r.data || r.requests || r || [];
  return Array.isArray(d) ? d : [];
};

function RequestRow({ req, onAction, onOverrideClick, isSupervisor, isHRManager, isBasicHR }) {
  const [acting, setActing] = useState('');

  const leaveTypeName = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.LeaveTypeName || req.leaveTypeName || '—';
  const empFullName = req.Employee?.FullName || req.employee?.fullName || req.EmployeeName || req.employeeName || '—';
  const status = req.Status || req.status || 'SUBMITTED';
  const id = req.LeaveRequestID || req.id;
  const isFinal = isFinalStatus(status);

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  return (
    <tr>
      <td>
        <div style={{ fontWeight: 500 }}>{leaveTypeName}</div>
        {!(isSupervisor || isHRManager) && <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{req.Reason || req.reason}</div>}
      </td>
      {(isSupervisor || isHRManager || isBasicHR) && <td><div style={{ fontWeight: 500 }}>{empFullName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{new Date(req.StartDate || req.startDate).toLocaleDateString()}</td>
      <td>{req.TotalDays ?? '—'}</td>
      <td><Badge status={status}>{STATUS_LABEL[status] || status}</Badge></td>
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {(isSupervisor || isHRManager) && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>Approve</button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>Reject</button>
            </>
          )}
          {isHRManager && isFinal && normStatus(status) !== 'CANCELLED' && onOverrideClick && (
            <button className="btn btn-ghost btn-sm" onClick={() => onOverrideClick(req)} disabled={!!acting}><Shield size={13}/> Override</button>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── ADMIN CONFIGURATION COMPONENTS (FULFILLING IMAGE REQUIREMENTS) ──────────
function LeaveTypeManager({ types, onAdd }) {
  const [newType, setNewType] = useState({ name: '', code: '', defaultDays: 21, minTenure: 0, noticePeriod: 0 });

  return (
    <div className="card p-4 mb-4">
      <div className="card-title mb-3"><Settings size={16}/> Manage Leave Types & Eligibility Rules</div>
      <div className="grid-2 gap-3 mb-3">
        <div className="form-group">
          <label className="form-label">Leave Name</label>
          <input className="form-input" placeholder="e.g. Annual Leave" onChange={e => setNewType({...newType, name: e.target.value})} />
        </div>
        <div className="form-group">
          <label className="form-label">Entitlement (Days)</label>
          <input className="form-input" type="number" defaultValue="21" onChange={e => setNewType({...newType, defaultDays: e.target.value})} />
        </div>
        <div className="form-group">
          <label className="form-label">Min Tenure (Months)</label>
          <input className="form-input" type="number" placeholder="0" onChange={e => setNewType({...newType, minTenure: e.target.value})} />
        </div>
        <div className="form-group">
          <label className="form-label">Notice Period (Days)</label>
          <input className="form-input" type="number" placeholder="2" onChange={e => setNewType({...newType, noticePeriod: e.target.value})} />
        </div>
      </div>
      <button className="btn btn-primary btn-sm mb-3" onClick={() => onAdd(newType)}>Initiate Leave Configuration</button>
      <div className="table-wrap">
        <table className="table-sm">
          <thead><tr><th>Type</th><th>Days</th><th>Rules</th></tr></thead>
          <tbody>
            {types.map((t, i) => (
              <tr key={i}>
                <td>{t.LeaveTypeName}</td>
                <td>{t.DefaultDays || 21}</td>
                <td className="small text-muted">{t.MinTenureMonths || 0}m tenure · {t.NoticePeriodDays || 0}d notice</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function HolidayManager({ holidays, onAdd }) {
  const [newHoliday, setNewHoliday] = useState({ name: '', date: '' });

  return (
    <div className="card p-4">
      <div className="card-title mb-2"><Calendar size={16}/> Set Calendars & Blocked Days</div>
      <p className="text-muted small mb-3">Dates here are excluded from leave calculations.</p>
      <div className="form-row">
        <input className="form-input" type="date" onChange={e => setNewHoliday({...newHoliday, date: e.target.value})} />
        <input className="form-input" placeholder="Holiday/Reason" onChange={e => setNewHoliday({...newHoliday, name: e.target.value})} />
        <button className="btn btn-primary" onClick={() => onAdd(newHoliday)}>Add</button>
      </div>
      <div className="mt-3 small" style={{ maxHeight: '120px', overflowY: 'auto' }}>
        {holidays.map((h, i) => (
          <div key={i} className="d-flex justify-content-between border-bottom p-1">
            <span>{new Date(h.HolidayDate || h.date).toLocaleDateString()}</span>
            <strong>{h.HolidayName || h.name}</strong>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── MAIN COMPONENT ──────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user } = useAuth();
  const posId = parseInt(user?.PositionID || user?.positionId, 10);
  const roleStr = (user?.role || user?.Role || '').toUpperCase();

  const isHRManager = posId === 1;
  const isSupervisor = posId === 2 || roleStr.includes('PROFESSOR') || roleStr.includes('MANAGER');
  const isBasicHR = (roleStr.includes('HR') || roleStr.includes('ADMIN')) && !isHRManager;

  const isManagement = isHRManager || isSupervisor || isBasicHR;
  const canDelegate = isHRManager || isSupervisor;

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);
  const [holidays, setHolidays] = useState([]);

  const [loadBal, setLoadBal] = useState(true);
  const [loadAll, setLoadAll] = useState(true);

  const [overrideReq, setOverrideReq] = useState(null); 
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);
  const [showAdjustmentModal, setShowAdjustmentModal] = useState(false);

  const loadData = useCallback(() => {
    setLoadBal(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r)));
    leaveAPI.getTypes().then(r => setTypes(toArr(r)));
    if (isHRManager) leaveAPI.listHolidays().then(r => setHolidays(toArr(r)));

    if (isManagement) {
      setLoadAll(true);
      const fetchMethod = isHRManager || isBasicHR ? leaveAPI.listAll() : leaveAPI.getManagerInbox();
      fetchMethod.then(r => setAll(toArr(r))).finally(() => setLoadAll(false));
    }
  }, [isHRManager, isSupervisor, isBasicHR, isManagement]);

  useEffect(() => { loadData(); }, [loadData]);

  const uniqueEmployees = Array.from(
    new Map(
      allRequests
        .filter(r => r.EmployeeID || r.employeeId)
        .map(r => [
          r.EmployeeID || r.employeeId,
          r.Employee?.FullName || r.employeeName || `User ${r.EmployeeID}`
        ])
    ).entries()
  ).map(([id, name]) => ({ id, name }));

  const handleAction = async (id, action) => {
    try {
      if (action === 'approve') await leaveAPI.approveReject(id, { decision: 'APPROVED' });
      else await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: 'Actioned by Admin' });
      toast.success('Updated successfully'); loadData();
    } catch (err) { toast.error(getErrMsg(err)); }
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard',    icon: BarChart2 },
    { id: 'history',   label: 'My History',   icon: Clock },
    ...(isManagement ? [ { id: 'all', label: isHRManager || isBasicHR ? 'Company Data' : 'Team Inbox', icon: Users } ] : []),
    ...(isHRManager ? [ { id: 'settings', label: 'Settings', icon: Settings } ] : []),
  ];

  return (
    <>
      <div className="page-header d-flex justify-content-between p-3">
        <div><h1>Leave Management</h1><p>Control requests, rules, and entitlements</p></div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}><Plus size={18}/> New Request</button>
      </div>

      <div className="tabs px-3">
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}><Icon size={14} style={{marginRight:6}}/>{label}</button>
        ))}
      </div>

      <div className="p-3">
        {tab === 'dashboard' && <div className="grid-4">{balances.map((b, i) => <BalanceCard key={i} balance={b} loading={loadBal} />)}</div>}

        {tab === 'all' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
            {canDelegate && (
              <div className="card p-3 mb-2">
                <div className="card-title small mb-2"><Users size={14}/> Delegate Authority</div>
                <button className="btn btn-sm btn-ghost" onClick={() => toast("Feature active in Team Settings")}>Initiate Delegation</button>
              </div>
            )}
            <div className="card table-wrap">
              <table>
                <thead><tr><th>Type</th><th>Employee</th><th>Period</th><th>Status</th><th>Actions</th></tr></thead>
                <tbody>{allRequests.map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onOverrideClick={setOverrideReq} isSupervisor={isSupervisor} isHRManager={isHRManager} isBasicHR={isBasicHR} />)}</tbody>
              </table>
            </div>
          </div>
        )}

        {tab === 'settings' && isHRManager && (
          <div className="settings-grid">
            <LeaveTypeManager types={leaveTypes} onAdd={d => leaveAPI.createType(d).then(loadData)} />
            <HolidayManager holidays={holidays} onAdd={d => leaveAPI.createHoliday(d).then(loadData)} />

            <div className="card p-4 mt-4">
              <div className="card-title mb-3"><Shield size={16}/> Define Leave Year Rules</div>
              <div className="form-group mb-3">
                <label className="small text-muted">Default Annual Entitlement</label>
                <input className="form-input" type="number" defaultValue="21" />
              </div>
              <div className="d-flex gap-2">
                <button className="btn btn-outline-primary" onClick={() => leaveAPI.syncPayroll({}).then(() => toast.success("Synced"))}>Validate & Apply Configs</button>
                <button className="btn btn-outline-danger" onClick={() => setShowAdjustmentModal(true)}>Adjust Leave Balances</button>
              </div>
            </div>
          </div>
        )}
      </div>

      {showAdjustmentModal && (
        <InlineModal title="Adjust Entitlement Calculations" onClose={() => setShowAdjustmentModal(false)}>
           <div className="form-group mb-3"><label>Target Employee</label>
             <select className="form-select" id="adjEmp">{uniqueEmployees.map(e => <option key={e.id} value={e.id}>{e.name}</option>)}</select>
           </div>
           <div className="form-group mb-3"><label>Add/Subtract Days</label><input type="number" className="form-input" id="adjDays" placeholder="e.g. 5 or -5" /></div>
           <button className="btn btn-primary w-full" onClick={() => {
             const data = { EmployeeID: document.getElementById('adjEmp').value, AdjustedDays: document.getElementById('adjDays').value };
             leaveAPI.adjustBalance(data).then(() => { toast.success("Balance Updated"); setShowAdjustmentModal(false); loadData(); });
           }}>Apply Configuration Update</button>
        </InlineModal>
      )}

      {overrideReq && isHRManager && (
        <InlineModal title="Authenticate Admin Decision" onClose={() => setOverrideReq(null)}>
          <p>Manual Override for <strong>{overrideReq.Employee?.FullName}</strong></p>
          <div className="d-flex gap-2 mt-4">
            <button className="btn btn-success" onClick={() => { handleAction(overrideReq.id, 'approve'); setOverrideReq(null); }}>Authenticate & Approve</button>
            <button className="btn btn-danger" onClick={() => { handleAction(overrideReq.id, 'reject'); setOverrideReq(null); }}>Authenticate & Reject</button>
          </div>
        </InlineModal>
      )}
    </>
  );
}
